const input = $input.first().json;
const body = input.body || input;

const fields = [
  'nombre_academia', 'nombre_profe', 'email', 'telefono',
  'ubicacion_direccion', 'ubicacion_localidad', 'horario_atencion',
  'banco', 'cbu', 'alias', 'linktree_url',
  'instagram', 'facebook', 'politica_cancelacion',
  'politica_recuperacion', 'politica_reembolso'
];

const values = [];
let hasUpdates = false;

for (const field of fields) {
  const value = body[field];
  if (value !== undefined && value !== null && value !== '') {
    const escaped = String(value).replace(/'/g, "''");
    values.push(`('${field}', '${escaped}', NOW())`);
    hasUpdates = true;
  }
}

let query = null;
if (hasUpdates) {
  query = `INSERT INTO academia_config (clave, valor, updated_at) 
VALUES ${values.join(', ')} 
ON CONFLICT (clave) DO UPDATE SET valor = EXCLUDED.valor, updated_at = NOW()
RETURNING clave, valor;`;
}

return [{
  json: {
    query,
    hasUpdates,
    values
  }
}];

const results = $input.all();
const config = {};

for (const row of results) {
  const data = row.json;
  if (data.clave && data.valor !== undefined) {
    config[data.clave] = data.valor;
  }
}

return [{
  json: {
    success: true,
    message: 'Configuración actualizada exitosamente',
    config
  }
}];

return [{
  json: {
    success: false,
    message: 'No hay campos para actualizar',
    config: {}
  }
}];
